Monster.Menu.prototype = {
    create: function() {
        this.add.image(0, 0, "bgMenu");
        this.logo = game.add.image(0, 5 * resolution, "preloadSprite01");
        this.logo.anchor.setTo(.5, 0);
        this.logo.x = this.world.centerX;
        this.timer_logo = 5e3;
        this.animation_logo();
        this.bnt_play = new Bouton(this.game, 0, 0, "buttonPlay", this.actionPlay, this);
        this.bnt_play.anchor.setTo(.5, .5);
        this.bnt_play.x = this.world.centerX;
        this.bnt_play.y = 375 * resolution;
        this.world.add(this.bnt_play);
        this.Mmenu = game.add.image(248 * resolution, 225 * resolution, "Mmenu");
        this.Mmenu.visible = false;
        this.musicbnt = game.add.image(258 * resolution, 240 * resolution, "micones", 1);
        this.musicbnt.inputEnabled = true;
        this.musicbnt.events.onInputDown.add(this.actionMusic, this);
        this.musicbnt.visible = false;
        this.world.add(this.musicbnt);
        this.mrgames = new Bouton(this.game, 50 * resolution, this.bnt_play.y + 30 * resolution, "mrgames", this.moregames, this);
        this.world.add(this.mrgames);
        this.res = new Bouton(this.game, 270 * resolution, this.mrgames.y, "reglage", this.reglage, this);
        this.world.add(this.res);
        this.bnt_credits = game.add.image(255 * resolution, 283 * resolution, "micones", 0);
        this.bnt_credits.inputEnabled = true;
        this.bnt_credits.events.onInputDown.add(this.funccredits, this);
        this.bnt_credits.visible = false;
        this.world.add(this.bnt_credits);
        this.acheiv = game.add.image(255 * resolution, 326 * resolution, "micones", 3);
        this.acheiv.inputEnabled = true;
        this.acheiv.events.onInputDown.add(this.resultat, this);
        this.acheiv.visible = false;
        this.world.add(this.acheiv);
        if (Music.enableMisic) {
            this.musicbnt.loadTexture("micones", 1)
        } else {
            this.musicbnt.loadTexture("micones", 2)
        }
        try {
            analytics.menu();
        } catch (e) {
            console.log("BOOSTERMEDIA_MAINMENU not implemented.")
        }
    },
    reglage: function() {
        if (this.Mmenu.visible) {
            this.Mmenu.visible = false;
            this.musicbnt.visible = false;
            this.bnt_credits.visible = false;
            this.acheiv.visible = false
        } else {
            this.Mmenu.visible = true;
            this.musicbnt.visible = true;
            this.bnt_credits.visible = true;
            this.acheiv.visible = true
        }
    },
    resultat: function() {
        this.game.state.start("resultat")
    },
    moregames: function() {

    },
    actionMusic: function() {
        Music.enableMisic = !Music.enableMisic;
        if (Music.enableMisic) {
            this.musicbnt.loadTexture("micones", 1);
            Music.music.resume()
        } else {
            this.musicbnt.loadTexture("micones", 2);
            Music.music.pause()
        }
    },
    actionPlay: function() {
        this.game.state.start("modes", true)
    },
    funccredits: function() {
        this.game.state.start("credits", true)
    },
    update: function() {
        this.timer_logo -= game.time.elapsed;
        if (this.timer_logo < 0) {
            this.animation_logo();
            this.timer_logo = 5e3
        }
    },
    animation_logo: function() {
        game.add.tween(this.logo.scale)
            .to({
                x: 1.05
            }, 2e3, Phaser.Easing.Quadratic.Out, true, 0)
            .to({
                x: 1
            }, 5e3, Phaser.Easing.Elastic.Out, true);
        game.add.tween(this.logo.scale)
            .to({
                y: 1.1
            }, 2e3, Phaser.Easing.Quadratic.Out, true, 50)
            .to({
                y: 1
            }, 5e3, Phaser.Easing.Elastic.Out, true)
    }
};
