Monster.Levels.prototype = {
    create: function() {
        this.initProprties();
        this.game.input.maxPointers = 1;
        this.mouve = false;
        this.game.add.image(0, 0, "nrm_bg");
        this.game.add.image(this.world.centerX, 130 * resolution, "bgPause0")
            .anchor.setTo(.5, 0);
        this.groupBnt = this.game.add.group();
        var framebnt;
        this.MaxNbrBnt = nombre_levels;
        this.Groupe_courant = Math.floor((play.numLevel - 1) / 6);
        this.group_led = game.add.group();
        for (var i = 0; i < 10; i++) {
            this.group_led.create((90 + i * 15) * resolution, 335 * resolution, "led", 0)
        }
        this.group_led.create(0, 335 * resolution, "led", 1);
        this.group_led.getAt(this.group_led.length - 1)
            .x = this.group_led.getAt(this.Groupe_courant)
            .x;
        var numtxt = 0;
        while (numtxt <= 11) {
            numtxt++;
            var button = new Bouton(this.game, 0, 0, "levelbnt", null, null, framebnt, framebnt);
            button.onInputUp.add(function() {
                if (this.txt.visible) {
                    play.numLevel = parseInt(this.txt.text);
                    this.game.state.start("play", true)
                }
            }, button);
            button.txt = new Phaser.BitmapText(this.game, 0 * resolution, 0 * resolution, "02", numtxt + this.Groupe_courant * 6 + "", 17 * resolution);
            button.kill();
            button.txt.visible = false;
            this.groupBnt.add(button);
            this.groupBnt.add(button.txt);
            this.Gr_buttons.push(button);
            if (numtxt % 6 == 0) {
                this.All_buttons.push(this.Gr_buttons);
                this.Gr_buttons = []
            }
        }
        this.positionnreBnts(this.All_buttons[0], 0, this.Groupe_courant);
        this.bnt_home = new Bouton(this.game, this.world.centerX, -30 * resolution, "homel", this.funcHome, this, 0, 0);
        this.world.add(this.bnt_home);
        this.buttonUp = new Bouton(this.game, 290 * resolution, 260 * resolution, "up", this.funcGrSuivant, this, 1, 1);
        this.world.add(this.buttonUp);
        this.buttonDown = new Bouton(this.game, 30 * resolution, this.buttonUp.y, "down", this.funcGrPrecedent, this, 1, 1);
        this.world.add(this.buttonDown);
        var nbr_etoiles_total = 0;
        for (var i = 0; i < sauvegarde.length; i++) {
            nbr_etoiles_total += sauvegarde[i].numetoile
        }
        var bb = game.add.image(262 * resolution, 56 * resolution, "lvlcnt");
        bb.anchor.setTo(.5, .5);
        bb.scale.setTo(1, .9);
        var bbb = game.add.image(55 * resolution, 56 * resolution, "lvlcnt");
        bbb.anchor.setTo(.5, .5);
        bbb.scale.setTo(1, .9);
        game.add.bitmapText(25 * resolution, 27 * resolution, "03", "LEVEL", 18 * resolution);
        if (+level + 1 < 10) this.nbr_levels(25);
        else this.nbr_levels(19);
        var star = game.add.image(247 * resolution, 23 * resolution, "etoile_total");
        if (nbr_etoiles_total < 10) this.nbr_etoiles(17, 18, star, nbr_etoiles_total);
        else if (nbr_etoiles_total >= 10 && nbr_etoiles_total < 100) this.nbr_etoiles(21, 17, star, nbr_etoiles_total);
        else this.nbr_etoiles(23, 16, star, nbr_etoiles_total)
    },
    nbr_etoiles: function(a, b, s, n) {
        game.add.bitmapText(s.x - a * resolution, 66 * resolution, "03", "" + n + "/" + nombre_levels * 3, b * resolution)
    },
    nbr_levels: function(a) {
        game.add.bitmapText(a * resolution, 65 * resolution, "03", "" + (+level + 1) + "/60", 18 * resolution)
    },
    initProprties: function() {
        this.groupBnt = null;
        this.All_buttons = [];
        this.Gr_buttons = [];
        this.translatTween = {
            y: 0
        };
        this.velocityY = 0;
        this.tween = null;
        this.mouve = false;
        this.isDown = null
    },
    funcHome: function() {
        this.game.state.start("modes", true)
    },
    positionnreBnts: function(groupBnts, tr, numG) {
        var endBnt = false;
        for (var jj = 0; jj < groupBnts.length; jj++) {
            if (endBnt) {
                groupBnts[jj].kill();
                groupBnts[jj].txt.visible = false;
                continue
            }
            if (!groupBnts[jj].exists) groupBnts[jj].revive();
            if (jj == 0) {
                groupBnts[jj].x = 102 * resolution;
                groupBnts[jj].y = 230 * resolution
            } else if (jj == 1) {
                groupBnts[jj].x = 162 * resolution;
                groupBnts[jj].y = 230 * resolution
            } else if (jj == 2) {
                groupBnts[jj].x = 222 * resolution;
                groupBnts[jj].y = 230 * resolution
            } else if (jj == 3) {
                groupBnts[jj].x = 102 * resolution;
                groupBnts[jj].y = 295 * resolution
            } else if (jj == 4) {
                groupBnts[jj].x = 162 * resolution;
                groupBnts[jj].y = 295 * resolution
            } else if (jj == 5) {
                groupBnts[jj].x = 222 * resolution;
                groupBnts[jj].y = 295 * resolution
            }
            groupBnts[jj].x += tr;
            if (numG * 6 + jj <= level) {
                framebnt = sauvegarde[numG * 6 + jj].numetoile;
                groupBnts[jj].txt.visible = true
            } else {
                framebnt = 4;
                groupBnts[jj].txt.visible = false
            }
            if (framebnt == 0) framebnt = 5;
            var numtext = numG * 6 + jj + 1;
            groupBnts[jj].txt.setText(numtext + "");
            groupBnts[jj].txt.x = groupBnts[jj].x - 16 * resolution;
            if (numtext < 10) groupBnts[jj].txt.x = groupBnts[jj].x - 9 * resolution;
            groupBnts[jj].txt.y = groupBnts[jj].y - 13 * resolution;
            groupBnts[jj].frame = framebnt;
            if (numtext == this.MaxNbrBnt) endBnt = true
        }
    },
    funcGrSuivant: function() {
        if (!this.mouve && this.Groupe_courant < Math.ceil(this.MaxNbrBnt / 6) - 1) {
            this.Groupe_courant++;
            this.setAnimation();
            this.isDown = true
        }
        this.group_led.getAt(this.group_led.length - 1)
            .x = this.group_led.getAt(this.Groupe_courant)
            .x
    },
    setAnimation: function() {
        this.mouve = true;
        this.translatTween.y = this.world.height;
        this.velocityY = -800 * resolution
    },
    funcGrPrecedent: function() {
        if (!this.mouve && this.Groupe_courant > 0) {
            this.Groupe_courant--;
            this.setAnimation();
            this.isDown = false
        }
        this.group_led.getAt(this.group_led.length - 1)
            .x = this.group_led.getAt(this.Groupe_courant)
            .x
    },
    killBnt: function(obj) {
        obj.kill();
        obj.txt.visible = false
    },
    animation: function() {
        this.translatTween.y += this.velocityY * this.game.time.elapsed * .001;
        if (this.isDown) {
            this.positionnreBnts(this.All_buttons[0], this.translatTween.y, this.Groupe_courant);
            this.positionnreBnts(this.All_buttons[1], this.translatTween.y - this.world.height, this.Groupe_courant - 1)
        } else {
            this.positionnreBnts(this.All_buttons[0], this.translatTween.y * -1, this.Groupe_courant);
            this.positionnreBnts(this.All_buttons[1], this.translatTween.y * -1 + this.world.height, this.Groupe_courant + 1)
        }
        if (this.translatTween.y <= 0) {
            this.positionnreBnts(this.All_buttons[0], 0, this.Groupe_courant);
            this.translatTween.y = 0;
            this.All_buttons[1].forEach(this.killBnt, this);
            this.mouve = false
        }
    },
    update: function() {
        if (this.mouve) {
            this.animation()
        }
        if (this.bnt_home.y <= 55 * resolution) {
            this.bnt_home.y += 5 * resolution
        }
    }
};
